+
+    let pool_clone = pool.clone();
+    let attempt_count = Arc::new(AtomicU32::new(0));
+    let ac = attempt_count.clone();
+
+    // Use retry to acquire from pool and do work
+    let result = with_retry(&policy, || {
+        let pool = pool_clone.clone();
