+        async move {
+            let guard = pool
+                .acquire()
+                .await
+                .map_err(|e| frankenterm_core::Error::Runtime(e.to_string()))?;
+            ac.fetch_add(1, Ordering::SeqCst);
+            drop(guard);
+            Ok::<_, frankenterm_core::Error>(true)
+        }
+    })
+    .await;
+
+    assert!(result.unwrap());
+    assert_eq!(attempt_count.load(Ordering::SeqCst), 1);
+}
